import{_ as r,m as a,k as s,ah as i}from"./chunks/framework.DYy1ogWd.js";const h=JSON.parse('{"title":"Notes de version","description":"","frontmatter":{},"headers":[],"relativePath":"fr/release-notes.md","filePath":"src/fr/release-notes.md"}'),t={name:"fr/release-notes.md"};function o(n,e,l,d,u,v){return s(),a("div",null,[...e[0]||(e[0]=[i('<h1 id="notes-de-version" tabindex="-1">Notes de version <a class="header-anchor" href="#notes-de-version" aria-label="Permalink to &quot;Notes de version&quot;">​</a></h1><h2 id="dernieres-versions-v0-8-x-—-avril-2026" tabindex="-1">Dernières versions (v0.8.x) — Avril 2026 <a class="header-anchor" href="#dernieres-versions-v0-8-x-—-avril-2026" aria-label="Permalink to &quot;Dernières versions (v0.8.x) — Avril 2026&quot;">​</a></h2><p>La gestion des <strong>menus de navigation</strong> a été bien améliorée : nouveau formulaire de création d&#39;éléments de menu, support de différents types d&#39;éléments, et correction de bugs liés à leur configuration. Les nouvelles pages créées apparaissent désormais automatiquement en bas de la liste. Plusieurs librairies ont été mises à jour (Vue, Vue Router, l&#39;éditeur de texte CKEditor, etc.).</p><h2 id="v0-8-2-—-avril-2026" tabindex="-1">v0.8.2 — Avril 2026 <a class="header-anchor" href="#v0-8-2-—-avril-2026" aria-label="Permalink to &quot;v0.8.2 — Avril 2026&quot;">​</a></h2><p>Possibilité de configurer les <strong>langues disponibles</strong> directement dans la configuration de l&#39;application. Mises à jour de dépendances.</p><h2 id="v0-8-1-—-avril-2026" tabindex="-1">v0.8.1 — Avril 2026 <a class="header-anchor" href="#v0-8-1-—-avril-2026" aria-label="Permalink to &quot;v0.8.1 — Avril 2026&quot;">​</a></h2><p>Corrections sur le système de <strong>plugins</strong> : les modules tableau de bord et paramètres d&#39;un plugin ne sont plus obligatoires, et chaque plugin indique maintenant s&#39;il possède une interface utilisateur.</p><h2 id="v0-8-0-—-mars-2026" tabindex="-1">v0.8.0 — Mars 2026 <a class="header-anchor" href="#v0-8-0-—-mars-2026" aria-label="Permalink to &quot;v0.8.0 — Mars 2026&quot;">​</a></h2><p>Nouvelle page de <strong>gestion des plugins</strong> avec activation/désactivation améliorée. Mise à jour vers Vite 7.</p><h2 id="v0-7-7-—-mars-2026" tabindex="-1">v0.7.7 — Mars 2026 <a class="header-anchor" href="#v0-7-7-—-mars-2026" aria-label="Permalink to &quot;v0.7.7 — Mars 2026&quot;">​</a></h2><p>Améliorations sur la <strong>gestion du contenu</strong> : filtre de recherche de pages dans la barre latérale, possibilité de réordonner les pages, et support des titres de liens dans les sections de page.</p><h2 id="v0-7-5-—-mars-2026" tabindex="-1">v0.7.5 — Mars 2026 <a class="header-anchor" href="#v0-7-5-—-mars-2026" aria-label="Permalink to &quot;v0.7.5 — Mars 2026&quot;">​</a></h2><p>En mode développement, accès aux données brutes d&#39;un élément de contenu pour faciliter le débogage. Mises à jour de dépendances.</p><h2 id="v0-7-4-—-fevrier-2026" tabindex="-1">v0.7.4 — Février 2026 <a class="header-anchor" href="#v0-7-4-—-fevrier-2026" aria-label="Permalink to &quot;v0.7.4 — Février 2026&quot;">​</a></h2><p>Les <strong>interfaces s&#39;adaptent mieux aux écrans de toutes tailles</strong> (responsive). Correction d&#39;un bug sur les paramètres des structures de données. Mises à jour de dépendances majeures (vue-i18n, CKEditor…).</p><h2 id="v0-7-3-—-fevrier-2026" tabindex="-1">v0.7.3 — Février 2026 <a class="header-anchor" href="#v0-7-3-—-fevrier-2026" aria-label="Permalink to &quot;v0.7.3 — Février 2026&quot;">​</a></h2><p>Nombreuses améliorations sur l&#39;<strong>éditeur visuel</strong> : meilleure gestion des champs de sections, adaptation du générateur de formulaires.</p><h2 id="v0-7-2-—-fevrier-2026" tabindex="-1">v0.7.2 — Février 2026 <a class="header-anchor" href="#v0-7-2-—-fevrier-2026" aria-label="Permalink to &quot;v0.7.2 — Février 2026&quot;">​</a></h2><p>Améliorations sur l&#39;<strong>assistant de configuration initiale</strong> (setup) : meilleure création de base de données, corrections de bugs. Mises à jour CKEditor et Vue.</p><h2 id="v0-7-1-—-fevrier-2026" tabindex="-1">v0.7.1 — Février 2026 <a class="header-anchor" href="#v0-7-1-—-fevrier-2026" aria-label="Permalink to &quot;v0.7.1 — Février 2026&quot;">​</a></h2><p>Le <strong>sélecteur d&#39;icônes</strong> dans les paramètres de l&#39;application peut maintenant être configuré pour retourner le nom de l&#39;icône.</p><h2 id="v0-7-0-—-fevrier-2026" tabindex="-1">v0.7.0 — Février 2026 <a class="header-anchor" href="#v0-7-0-—-fevrier-2026" aria-label="Permalink to &quot;v0.7.0 — Février 2026&quot;">​</a></h2><p>Refonte complète du <strong>système d&#39;accès et d&#39;authentification</strong>, avec de nouveaux services API et une architecture plus propre.</p><h2 id="v0-6-x-—-decembre-2025-–-janvier-2026" tabindex="-1">v0.6.x — Décembre 2025 – Janvier 2026 <a class="header-anchor" href="#v0-6-x-—-decembre-2025-–-janvier-2026" aria-label="Permalink to &quot;v0.6.x — Décembre 2025 – Janvier 2026&quot;">​</a></h2><p>Gestion des <strong>métadonnées et de la visibilité des vidéos</strong>. Corrections de bugs sur l&#39;éditeur visuel.</p><h2 id="v0-6-0-—-decembre-2025" tabindex="-1">v0.6.0 — Décembre 2025 <a class="header-anchor" href="#v0-6-0-—-decembre-2025" aria-label="Permalink to &quot;v0.6.0 — Décembre 2025&quot;">​</a></h2><p>Lancement de l&#39;<strong>éditeur visuel</strong> : gestion des sections de pages directement depuis l&#39;interface, avec une barre latérale dédiée.</p><h2 id="v0-5-0-rc-x-—-septembre–novembre-2025" tabindex="-1">v0.5.0-rc.x — Septembre–Novembre 2025 <a class="header-anchor" href="#v0-5-0-rc-x-—-septembre–novembre-2025" aria-label="Permalink to &quot;v0.5.0-rc.x — Septembre–Novembre 2025&quot;">​</a></h2><p>Améliorations progressives de l&#39;éditeur visuel : copie de données entre sections, réorganisation par glisser-déposer, mode prévisualisation, meilleure gestion des modèles de contenu.</p><h2 id="v0-5-0-rc-1-—-septembre-2025" tabindex="-1">v0.5.0-rc.1 — Septembre 2025 <a class="header-anchor" href="#v0-5-0-rc-1-—-septembre-2025" aria-label="Permalink to &quot;v0.5.0-rc.1 — Septembre 2025&quot;">​</a></h2><p>Grande mise à jour : refonte de la mise en page principale, amélioration de la médiathèque, montée de version de CKEditor.</p><h2 id="v0-0-17-—-aout-2025" tabindex="-1">v0.0.17 — Août 2025 <a class="header-anchor" href="#v0-0-17-—-aout-2025" aria-label="Permalink to &quot;v0.0.17 — Août 2025&quot;">​</a></h2><p>Optimisations des performances : requêtes mises en cache pour les articles, newsletters, et autres données.</p><h2 id="v0-0-16-—-mai-2025" tabindex="-1">v0.0.16 — Mai 2025 <a class="header-anchor" href="#v0-0-16-—-mai-2025" aria-label="Permalink to &quot;v0.0.16 — Mai 2025&quot;">​</a></h2><p>Mise en place du <strong>système de plugins</strong>.</p><h2 id="v0-0-14-—-avril-2025" tabindex="-1">v0.0.14 — Avril 2025 <a class="header-anchor" href="#v0-0-14-—-avril-2025" aria-label="Permalink to &quot;v0.0.14 — Avril 2025&quot;">​</a></h2><p>Intégration d&#39;<strong>APIs de traduction automatique</strong> dans les champs multilingues. Import et export des utilisateurs.</p><h2 id="v0-0-13-—-mars-2025" tabindex="-1">v0.0.13 — Mars 2025 <a class="header-anchor" href="#v0-0-13-—-mars-2025" aria-label="Permalink to &quot;v0.0.13 — Mars 2025&quot;">​</a></h2><p>Nouveaux types de champs dans le générateur de formulaires : date/heure, plages horaires, mois, trimestre, semaine.</p><h2 id="v0-0-10-—-mars-2025" tabindex="-1">v0.0.10 — Mars 2025 <a class="header-anchor" href="#v0-0-10-—-mars-2025" aria-label="Permalink to &quot;v0.0.10 — Mars 2025&quot;">​</a></h2><p>Ajout de champs liste et liste multilingue dans le générateur de formulaires.</p><h2 id="v0-0-8-—-fevrier-2025" tabindex="-1">v0.0.8 — Février 2025 <a class="header-anchor" href="#v0-0-8-—-fevrier-2025" aria-label="Permalink to &quot;v0.0.8 — Février 2025&quot;">​</a></h2><p>Améliorations de l&#39;interface mobile (header, affichage général). Limite configurable sur les sélections multiples.</p><h2 id="v0-0-5-—-janvier-2025" tabindex="-1">v0.0.5 — Janvier 2025 <a class="header-anchor" href="#v0-0-5-—-janvier-2025" aria-label="Permalink to &quot;v0.0.5 — Janvier 2025&quot;">​</a></h2><p>Nombreuses corrections et nouvelles fonctionnalités : gestion des permaliens, sélecteur de médias, mise à jour auto des sections, affichage de la position des sections, correctifs de performance et de pagination.</p><h2 id="v0-0-2-—-janvier-2025" tabindex="-1">v0.0.2 — Janvier 2025 <a class="header-anchor" href="#v0-0-2-—-janvier-2025" aria-label="Permalink to &quot;v0.0.2 — Janvier 2025&quot;">​</a></h2><p>Première version publique : tableau de bord avec carte des visites, gestion des vidéos.</p>',47)])])}const m=r(t,[["render",o]]);export{h as __pageData,m as default};
